import{_ as a,o as i,c as t,a0 as n}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"Kingdom Analytics","description":"","frontmatter":{},"headers":[],"relativePath":"analytics/kingdom.md","filePath":"analytics/kingdom.md"}'),o={name:"analytics/kingdom.md"};function l(s,e,r,c,d,h){return i(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="kingdom-analytics" tabindex="-1">Kingdom Analytics <a class="header-anchor" href="#kingdom-analytics" aria-label="Permalink to &quot;Kingdom Analytics&quot;">​</a></h1><p>The <strong>Kingdom</strong> tab is the highest-level analytics view in the app. It rolls up tracked players, alliances, scores, and participation across a whole kingdom.</p><p>If this is your first premium analytics page, see <a href="./../subscriptions/premium-features.html">Premium Features</a> for the general locked/active pattern. This page focuses on who can see the tab and what it contains.</p><blockquote><p>Screenshot placeholder: <code>analytics-kingdom.png</code> (S49)</p></blockquote><h2 id="who-can-open-this-tab" tabindex="-1">Who can open this tab <a class="header-anchor" href="#who-can-open-this-tab" aria-label="Permalink to &quot;Who can open this tab&quot;">​</a></h2><p>There are two valid paths:</p><ul><li><code>Supreme Admin</code> and <code>King</code> users can open kingdom analytics as part of their normal kingdom-level scope.</li><li><code>Alliance Leader</code> and <code>Co-Leader</code> users can open a limited kingdom view <strong>only</strong> through an <strong>accepted</strong> premium kingdom grant that includes the <code>kingdom_analytics_for_granted_alliances</code> feature.</li></ul><p>This is the important rule: <strong>ordinary kingdom membership does not unlock the Kingdom tab for alliance leadership.</strong> Being part of a kingdom is not enough by itself.</p><p>If you are using granted access, read:</p><ul><li><a href="./../subscriptions/accept-grant.html">Accept a Premium Offer</a></li><li><a href="./../subscriptions/kingdom-grants.html">Kingdom Grants</a></li></ul><h2 id="what-granted-access-looks-like" tabindex="-1">What granted access looks like <a class="header-anchor" href="#what-granted-access-looks-like" aria-label="Permalink to &quot;What granted access looks like&quot;">​</a></h2><p>When the tab is coming from an accepted grant, it opens as a reduced kingdom view. You still get useful kingdom-wide comparisons and trends, but cross-alliance player detail is intentionally reduced.</p><p>That means granted access is best for:</p><ul><li>comparing alliances</li><li>spotting participation trends</li><li>seeing kingdom totals</li></ul><p>It is not meant to expose every player-level detail across every alliance.</p><h2 id="what-you-will-see" tabindex="-1">What you will see <a class="header-anchor" href="#what-you-will-see" aria-label="Permalink to &quot;What you will see&quot;">​</a></h2><p>The Kingdom tab can include:</p><ul><li>top summary cards for tracked players, alliances, kingdom power, total score, and participation</li><li>kingdom trend charts</li><li>category or event-discipline summaries</li><li>alliance standings</li><li>top players or kingdom champions when your access level allows that detail</li></ul><p>Selecting an alliance usually opens the Alliance tab for a closer look.</p><h2 id="when-this-tab-is-hidden" tabindex="-1">When this tab is hidden <a class="header-anchor" href="#when-this-tab-is-hidden" aria-label="Permalink to &quot;When this tab is hidden&quot;">​</a></h2><p>The tab stays hidden when:</p><ul><li>you are alliance-scoped and no accepted grant is active</li><li>the accepted grant does not include the kingdom analytics sharing feature</li><li>your role only has alliance-level access</li></ul><p>If you expected to see it, check the alliance&#39;s effective premium source first, then confirm the accepted grant really carries the sharing feature.</p><h2 id="good-practice" tabindex="-1">Good practice <a class="header-anchor" href="#good-practice" aria-label="Permalink to &quot;Good practice&quot;">​</a></h2><ul><li>Use the Kingdom tab to compare alliances before drilling down.</li><li>Treat granted kingdom analytics as a summary view, not a full kingdom admin screen.</li><li>If you need player-level follow-up, continue into <a href="./alliance.html">Alliance Analytics</a> or <a href="./player-cross-event.html">Player Cross-Event Analytics</a>.</li></ul>',25)])])}const u=a(o,[["render",l]]);export{m as __pageData,u as default};
